configuration.encoder:
// Retrieve details from the RPC call
var rpcMethod = msg.method;
var rpcParams = msg.params || {};

var bytes = [];
var fPort = 1; // ESP32 接收指令的目标端口

if (rpcMethod === "resetAlarm" || rpcParams.command === 0xF3) {
    // 0xF3 Downlink - Manual Reset Alarm / Mute
    bytes = [0xF3];
} else if (rpcMethod === "hydrationReminder" || rpcParams.command === 0xF4) {
    // 0xF4 Downlink - Aggressive Hydration reminder
    bytes = [0xF4];
} else if (rpcMethod === "setExternalWBGT" || rpcParams.command === 0xF2) {
    // 0xF2 Downlink - Set External Sensor WBGT Calibration
    var wbgtFloat = rpcParams.wbgtFloat;
    if (wbgtFloat === undefined && rpcParams.wbgtRaw !== undefined) {
        wbgtFloat = rpcParams.wbgtRaw / 10.0;
    }

    // Scale float by 10 and convert to uint16
    var rawVal = Math.round(wbgtFloat * 10);

    // Split into 2 bytes (big endian)
    var highByte = (rawVal >> 8) & 0xFF;
    var lowByte = rawVal & 0xFF;

    bytes = [0xF2, highByte, lowByte];
} else if (rpcParams.command === 0xF1) {
    // 0xF1 Downlink - General test vibration
    bytes = [0xF1];
}

// Convert byte array to Base64 (TTN Downlink standard)
var base64Payload = btoa(String.fromCharCode.apply(null, bytes));

// 🚀 核心映射修复：将 ThingsBoard 的设备名转换为 TTN 认识的 "lilygo"
var devId = metadata.deviceName;
if (devId === "Device 70B3D57ED00771F0" || devId.indexOf("70B3D57ED00771F0") !== -1) {
    devId = "lilygo";
} else {
    // 降级保护：转换成小写以符合 TTN 命名规范
    devId = devId.replace("Device ", "").toLowerCase();
}

return {
    contentType: "JSON",
    data: JSON.stringify({
        downlinks: [{
            f_port: fPort,
            frm_payload: base64Payload,
            priority: "NORMAL",
            confirmed: false
        }]
    }),
    metadata: {
        devId: devId // 此时会输出完美的 "lilygo"！
    }
};
